import { createSlice, PayloadAction } from '@reduxjs/toolkit';

interface ErpMesState {
  loading: boolean;
}

const erpMesSlice = createSlice({
  name: 'erpMes',
  initialState: {
    loading: false,
  } as ErpMesState,
  reducers: {
    setLoading(state, { payload }: PayloadAction<boolean>) {
      state.loading = payload;
    },
  },
});

export const { setLoading } = erpMesSlice.actions;
export default erpMesSlice.reducer;
